module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output valid_out,
    output [9:0] data_out
);
    reg [1:0] count;
    reg [9:0] data_temp, data_out_reg;
    reg valid_out_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 2'd0;
            data_temp <= 10'd0;
            data_out_reg <= 10'd0;
            valid_out_reg <= 1'b0;
        end
        else begin
            if(valid_in == 1'b1) begin
                if(count == 2'd3) begin
                    count <= 2'd0;
                    data_out_reg <= data_temp + data_in;
                    valid_out_reg <= 1'b1;
                end
                else begin
                    count <= count + 1'b1;
                    data_temp <= data_temp + data_in;
                    valid_out_reg <= 1'b0;
                end
            end
            else begin
                valid_out_reg <= 1'b0;
            end
        end
    end
    assign valid_out = valid_out_reg;
    assign data_out = data_out_reg;
endmodule
